1	'use client';
2	
3	import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
4	import dynamic from 'next/dynamic';
5	import { notFound } from 'next/navigation';
6	import ErrorBoundary from '../../../components/ErrorBoundary';
7	import { productsService, ProductsServiceError } from '../../../services/productsService';
8	import { ProductCardData } from '../../../utils/productDataMapper';
9	import { Product } from '../../../types/medusa';
10	import { useRetry } from '../../../hooks/useRetry';
11	import { isValidHandle, generateProductHandle } from '../../../utils/productHandleGenerator';
12	import { useCart } from '../../../contexts/CartContext';
13	import { useWishlist } from '../../../contexts/WishlistContext';
14	import { medusaApiClient } from '../../../utils/medusaApiClient';
15	import LoadingSpinner from '../../../components/LoadingSpinner/LoadingSpinner';
16	import DynamicSvgEffect from '../../../components/DynamicSvgEffect';
17	import Reviews from './Reviews';
18	import styles from './ProductDetailPage.module.css';
19	
20	// Defer the similar-products grid — it lives below the fold, behind a
21	// `content-visibility: auto` wrapper, so the user can't see it until they
22	// scroll near it. Skipping it on the initial render path lets the above-fold
23	// content paint sooner.
24	const SimilarProductsSection = dynamic(() => import('./SimilarProductsSection'), { ssr: false });
25	
26	interface ProductDetailPageProps {
27	  params: Promise<{ handle: string }>;
28	}
29	
30	interface PageState {
31	  product: Product | null;
32	  productData: ProductCardData | null;
33	  loading: boolean;
34	  error: ProductsServiceError | null;
35	  isAddingToCart: boolean;
36	  addToCartSuccess: boolean;
37	  addToCartError: string | null;
38	}
39	
40	const VIEW_LABELS = ['Front', 'Three-quarter', 'Profile', 'Detail', 'In situ'];
41	
42	// ─── tiny inline icons ─────────────────────────────────────────────────
43	const Icon = ({ children }: { children: React.ReactNode }) => (
44	  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
45	    {children}
46	  </svg>
47	);
48	const PlusI = () => <Icon><path d="M12 5v14" /><path d="M5 12h14" /></Icon>;
49	const MinusI = () => <Icon><path d="M5 12h14" /></Icon>;
50	const HeartI = ({ filled }: { filled?: boolean }) => (
51	  <svg width="20" height="20" viewBox="0 0 24 24" fill={filled ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
52	    <path d="M12 21s-7-4.5-9.5-9A5.5 5.5 0 0 1 12 6a5.5 5.5 0 0 1 9.5 6c-2.5 4.5-9.5 9-9.5 9z" />
53	  </svg>
54	);
55	const ChiselI = () => <Icon><path d="M14 4l6 6-9 9-6-6z" /><path d="m4 20 4-1" /></Icon>;
56	const ShieldI = () => <Icon><path d="M12 3 4 6v6c0 5 3.5 8 8 9 4.5-1 8-4 8-9V6z" /></Icon>;
57	const TruckI = () => (
58	  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
59	    <path d="M3 7h11v8H3z" /><path d="M14 10h4l3 3v2h-7" /><circle cx="7" cy="17" r="2" /><circle cx="17" cy="17" r="2" />
60	  </svg>
61	);
62	const RefreshI = () => <Icon><path d="M3 12a9 9 0 0 1 15.5-6.4L21 8" /><path d="M21 3v5h-5" /><path d="M21 12a9 9 0 0 1-15.5 6.4L3 16" /><path d="M3 21v-5h5" /></Icon>;
63	const CloseI = () => <Icon><path d="M6 6l12 12" /><path d="M6 18 18 6" /></Icon>;
64	const ArrowL = () => <Icon><path d="M15 6l-6 6 6 6" /></Icon>;
65	const ArrowR = () => <Icon><path d="M9 6l6 6-6 6" /></Icon>;
66	// ─── description ──────────────────────────────────────────────────────
67	const Description = ({ text }: { text: string }) => (
68	  <div className={styles.description}>
69	    <h3>Description</h3>
70	    <p>{text}</p>
71	  </div>
72	);
73	
74	// ─── mosaic gallery ────────────────────────────────────────────────────
75	const Gallery = ({
76	  images,
77	  activeIdx,
78	  setActiveIdx,
79	  onOpenLightbox,
80	  productTitle,
81	}: {
82	  images: string[];
83	  activeIdx: number;
84	  setActiveIdx: (i: number) => void;
85	  onOpenLightbox: (i: number) => void;
86	  productTitle: string;
87	}) => {
88	  if (images.length === 0) return null;
89	
90	  return (
91	    <div className={styles.gallery}>
92	      <div className={styles.mosaicStack}>
93	        {images.map((src, i) => {
94	          const offset = i - activeIdx;
95	          const isActive = i === activeIdx;
96	          // Skip cards fully outside the visible stack window — they paint
97	          // at opacity 0 anyway, and rendering them keeps GPU layers alive
98	          // for nothing.
99	          if (Math.abs(offset) > 2) return null;
100	          return (
101	            <div
102	              key={`${src}-${i}`}
103	              className={`${styles.mosCard} ${isActive ? styles.mosCardActive : ''}`}
104	              onClick={() => (isActive ? onOpenLightbox(i) : setActiveIdx(i))}
105	              style={{
106	                transform: `translate(${offset * 22}px, ${Math.abs(offset) * 18}px) scale(${1 - Math.abs(offset) * 0.06}) rotate(${offset * 1.5}deg)`,
107	                zIndex: 10 - Math.abs(offset),
108	                opacity: isActive ? 1 : 0.6,
109	                cursor: isActive ? 'zoom-in' : 'pointer',
110	              }}
111	            >
112	              <img src={src} alt={isActive ? productTitle : ''} loading={isActive ? 'eager' : 'lazy'} decoding="async" />
113	              {isActive && (
114	                <>
115	                  <div className={styles.frameCounter}>
116	                    {String(i + 1).padStart(2, '0')} / {String(images.length).padStart(2, '0')}
117	                  </div>
118	                  {VIEW_LABELS[i] && <div className={styles.viewTag}>{VIEW_LABELS[i]}</div>}
119	                </>
120	              )}
121	            </div>
122	          );
123	        })}
124	      </div>
125	      <div className={styles.mosaicScrubber}>
126	        {images.map((_, i) => (
127	          <button
128	            key={i}
129	            type="button"
130	            className={`${styles.scrubDot} ${i === activeIdx ? styles.scrubDotActive : ''}`}
131	            onClick={() => setActiveIdx(i)}
132	            aria-label={`View ${i + 1}`}
133	          >
134	            <span className={styles.scrubNum}>{String(i + 1).padStart(2, '0')}</span>
135	            <span className={styles.scrubLine} />
136	          </button>
137	        ))}
138	      </div>
139	    </div>
140	  );
141	};
142	
143	// ─── material story ───────────────────────────────────────────────────
144	const MaterialStory = () => (
145	  <section className={styles.materialStory}>
146	    <div className={styles.msInner}>
147	      <img className={styles.msPeacock} src="/theme_images/peacock-art-white.png" alt="" aria-hidden="true" />
148	      <div className={styles.msEyebrow}><span className={styles.eyebrowGlyph} /> The Stone</div>
149	      <h3 className={styles.msTitle}>
150	        Quarried near Tadipatri,<br />chiselled by hand.
151	      </h3>
152	      <p className={styles.msBody}>
153	        The block was lifted from the Andhra granite belt — a stone so dense it rings when struck.
154	        Patient relief work follows: shaping the silhouette, drawing the brow, deepening the gaze.
155	        No two pieces leave the atelier identical.
156	      </p>
157	      <div className={styles.msStats}>
158	        <div><span className={styles.msNum}>2.74</span><span className={styles.msCap}>g/cm³ density</span></div>
159	        <div><span className={styles.msNum}>90+</span><span className={styles.msCap}>days in carving</span></div>
160	        <div><span className={styles.msNum}>∞</span><span className={styles.msCap}>generational</span></div>
161	      </div>
162	    </div>
163	  </section>
164	);
165	
166	// ─── trust strip ──────────────────────────────────────────────────────
167	const CraftStrip = () => {
168	  const items = [
169	    { icon: <ShieldI />, t: 'Authenticated', s: 'Hand-signed by the master carver' },
170	    { icon: <TruckI />, t: 'Insured shipping', s: 'Crated, padded and tracked' },
171	    { icon: <RefreshI />, t: '7-day returns', s: 'If the form does not move you' },
172	  ];
173	  return (
174	    <div className={styles.craftStrip}>
175	      <div className={styles.csInner}>
176	        {items.map((it, i) => (
177	          <div key={i} className={styles.csItem}>
178	            <span className={styles.csIcon}>{it.icon}</span>
179	            <div>
180	              <div className={styles.csTitle}>{it.t}</div>
181	              <div className={styles.csSub}>{it.s}</div>
182	            </div>
183	          </div>
184	        ))}
185	      </div>
186	    </div>
187	  );
188	};
189	
190	// ─── lightbox ─────────────────────────────────────────────────────────
191	const Lightbox = ({
192	  open, idx, images, onClose, onPrev, onNext,
193	}: {
194	  open: boolean;
195	  idx: number;
196	  images: string[];
197	  onClose: () => void;
198	  onPrev: () => void;
199	  onNext: () => void;
200	}) => {
201	  useEffect(() => {
202	    if (!open) return;
203	    const onKey = (e: KeyboardEvent) => {
204	      if (e.key === 'Escape') onClose();
205	      else if (e.key === 'ArrowLeft') onPrev();
206	      else if (e.key === 'ArrowRight') onNext();
207	    };
208	    window.addEventListener('keydown', onKey);
209	    return () => window.removeEventListener('keydown', onKey);
210	  }, [open, onClose, onPrev, onNext]);
211	
212	  // Skip rendering entirely when closed — the previous version kept the
213	  // dialog DOM mounted with display:none, which still cost layout/parse work.
214	  if (!open) return null;
215	  return (
216	    <div className={`${styles.lightbox} ${styles.lightboxOpen}`} role="dialog" aria-modal="true">
217	      <button className={`${styles.lbBtn} ${styles.lbClose}`} onClick={onClose} aria-label="Close"><CloseI /></button>
218	      <button className={`${styles.lbBtn} ${styles.lbPrev}`} onClick={onPrev} aria-label="Previous"><ArrowL /></button>
219	      <button className={`${styles.lbBtn} ${styles.lbNext}`} onClick={onNext} aria-label="Next"><ArrowR /></button>
220	      {images[idx] && <img src={images[idx]} alt="" />}
221	      <div className={styles.lbCounter}>
222	        {String(idx + 1).padStart(2, '0')} / {String(images.length).padStart(2, '0')}
223	      </div>
224	    </div>
225	  );
226	};
227	
228	// ─── main component ───────────────────────────────────────────────────
229	export default function ProductDetailPage({ params }: ProductDetailPageProps) {
230	  const [handle, setHandle] = useState<string | null>(null);
231	  const { addToCart, loading: cartLoading } = useCart();
232	  const { isInWishlist, toggleWishlist, pendingIds: wishPending, isAuthenticated: wishAuth } = useWishlist();
233	
234	  const [state, setState] = useState<PageState>({
235	    product: null,
236	    productData: null,
237	    loading: true,
238	    error: null,
239	    isAddingToCart: false,
240	    addToCartSuccess: false,
241	    addToCartError: null,
242	  });
243	  const [qty, setQty] = useState(1);
244	  const [activeIdx, setActiveIdx] = useState(0);
245	  const [lightbox, setLightbox] = useState<{ open: boolean; idx: number }>({ open: false, idx: 0 });
246	
247	  const isMounted = useRef(true);
248	  useEffect(() => {
249	    isMounted.current = true;
250	    return () => { isMounted.current = false; };
251	  }, []);
252	
253	  const update = useCallback((u: Partial<PageState>) => {
254	    if (!isMounted.current) return;
255	    setState(prev => ({ ...prev, ...u }));
256	  }, []);
257	
258	  const { retryCount, isRetrying, canRetry, retry, reset } = useRetry({
259	    maxRetries: 3, initialDelay: 1000, backoffMultiplier: 2, maxDelay: 10000,
260	  });
261	
262	  // resolve route params
263	  useEffect(() => {
264	    params.then(p => {
265	      if (!isValidHandle(p.handle)) { notFound(); return; }
266	      setHandle(p.handle);
267	    });
268	  }, [params]);
269	
270	  const fetchProduct = useCallback(async () => {
271	    if (!handle) return;
272	    try {
273	      update({ loading: true, error: null, addToCartError: null, addToCartSuccess: false });
274	      try {
275	        const [productData, rawProduct] = await Promise.all([
276	          productsService.fetchProductByHandle(handle),
277	          medusaApiClient.getProductByHandle(handle),
278	        ]);
279	        if (!isMounted.current) return;
280	        update({ productData, product: rawProduct, loading: false });
281	        reset();
282	      } catch (handleError) {
283	        // Fall back: search all products by generated handle
284	        const all = await productsService.fetchProducts();
285	        const match = all.find(p => generateProductHandle(p.title) === handle);
286	        if (!match) { notFound(); return; }
287	        let rawProduct: Product | null = null;
288	        try { rawProduct = await medusaApiClient.getProduct(match.id); } catch { /* tolerated */ }
289	        if (!isMounted.current) return;
290	        update({ productData: match, product: rawProduct, loading: false });
291	        reset();
292	      }
293	    } catch (err) {
294	      if (!isMounted.current) return;
295	      const e = err as ProductsServiceError;
296	      if (e.type === 'api' && e.originalError && 'status' in e.originalError && (e.originalError as any).status === 404) {
297	        notFound(); return;
298	      }
299	      update({ error: e, loading: false });
300	    }
301	  }, [handle, update, reset]);
302	
303	  useEffect(() => { if (handle) fetchProduct(); }, [handle, fetchProduct]);
304	
305	  const handleRetry = useCallback(async () => {
306	    if (!canRetry || !isMounted.current) return;
307	    try { await retry(fetchProduct); } catch { /* error handled inside */ }
308	  }, [retry, fetchProduct, canRetry]);
309	
310	  // build gallery image list from real product data
311	  const images = useMemo(() => {
312	    const out: string[] = [];
313	    const seen = new Set<string>();
314	    const push = (u?: string | null) => {
315	      if (!u) return;
316	      if (seen.has(u)) return;
317	      seen.add(u);
318	      out.push(u);
319	    };
320	    if (state.product?.images?.length) {
321	      state.product.images.forEach(img => push(img.url));
322	    }
323	    push(state.productData?.foregroundImage);
324	    push(state.productData?.backgroundImage);
325	    return out;
326	  }, [state.product, state.productData]);
327	
328	  // keep active index in range when images change
329	  useEffect(() => {
330	    if (activeIdx >= images.length && images.length > 0) setActiveIdx(0);
331	  }, [images.length, activeIdx]);
332	
333	  // ─── add to cart (mirrors original logic) ────────────────────────
334	  const handleAddToCart = useCallback(async () => {
335	    if (!addToCart || !state.productData || !state.product) return;
336	
337	    if (!state.productData.inStock) {
338	      const allowBackorder = state.productData.inventory?.allowBackorder;
339	      if (!allowBackorder) {
340	        update({ addToCartError: 'This product is currently out of stock.', addToCartSuccess: false });
341	        return;
342	      }
343	    }
344	    if (!state.product.variants?.length) {
345	      update({ addToCartError: 'This product has no available variants.', addToCartSuccess: false });
346	      return;
347	    }
348	
349	    let selectedVariant = null;
350	    for (const v of state.product.variants) {
351	      let hasStock = false;
352	      if (typeof v.inventory_quantity === 'number' && v.inventory_quantity > 0) hasStock = true;
353	      else if (v.inventory_items?.length) {
354	        let avail = 0;
355	        for (const ii of v.inventory_items) {
356	          for (const lvl of ii.inventory?.location_levels || []) avail += lvl?.available_quantity || 0;
357	        }
358	        hasStock = avail >= qty;
359	      } else if (!v.manage_inventory) hasStock = true;
360	      else if (v.manage_inventory && state.productData.inStock) hasStock = true;
361	      if (!hasStock && v.allow_backorder) hasStock = true;
362	      if (hasStock) { selectedVariant = v; break; }
363	    }
364	    if (!selectedVariant) {
365	      update({ addToCartError: 'No product variant with sufficient stock is available.', addToCartSuccess: false });
366	      return;
367	    }
368	
369	    update({ isAddingToCart: true, addToCartError: null, addToCartSuccess: false });
370	    try {
371	      let estimatedUnitPrice: number | undefined;
372	      if (selectedVariant.prices?.length) {
373	        estimatedUnitPrice = Number(selectedVariant.prices[0].amount || 0) / 100;
374	      }
375	      await addToCart(selectedVariant.id, qty, estimatedUnitPrice);
376	      update({ addToCartSuccess: true });
377	      setTimeout(() => update({ addToCartSuccess: false }), 3000);
378	    } catch (err) {
379	      let msg = 'Failed to add item to cart. Please try again.';
380	      if (err instanceof Error) {
381	        if (err.message.includes('out of stock') || err.message.includes('insufficient stock')) {
382	          msg = 'This item is currently out of stock or has insufficient quantity available.';
383	        } else if (err.message.includes('cart not found')) {
384	          msg = 'Your cart session has expired. Please refresh the page and try again.';
385	        } else msg = err.message;
386	      }
387	      update({ addToCartError: msg });
388	      setTimeout(() => update({ addToCartError: null }), 5000);
389	    } finally {
390	      update({ isAddingToCart: false });
391	    }
392	  }, [addToCart, state.product, state.productData, qty, update]);
393	
394	  // ─── render: handle resolution ───────────────────────────────────
395	  if (!handle) {
396	    return (
397	      <div className={styles.stateWrap}>
398	        <div>
399	          <h1 className={styles.stateTitle}>Loading…</h1>
400	        </div>
401	      </div>
402	    );
403	  }
404	
405	  if (state.loading || isRetrying) {
406	    return (
407	      <div className={styles.stateWrap}>
408	        <div>
409	          <LoadingSpinner size="medium" color="primary" />
410	          <p className={styles.stateMsg} style={{ marginTop: '1rem' }}>Loading product…</p>
411	        </div>
412	      </div>
413	    );
414	  }
415	
416	  if (state.error) {
417	    return (
418	      <div className={styles.stateWrap}>
419	        <div>
420	          <h1 className={styles.stateTitle}>Error Loading Product</h1>
421	          <p className={styles.stateMsg}>{state.error.message}</p>
422	          {canRetry && (
423	            <button className={styles.retryBtn} onClick={handleRetry}>
424	              Try Again {retryCount > 0 && `(${retryCount}/3)`}
425	            </button>
426	          )}
427	        </div>
428	      </div>
429	    );
430	  }
431	
432	  if (!state.productData) { notFound(); return null; }
433	
434	  const product = state.productData;
435	  const rawProduct = state.product;
436	  const currency = product.currency || 'INR';
437	  const fmt = (n?: number) => (typeof n === 'number'
438	    ? (currency === 'INR' ? `₹ ${n.toLocaleString('en-IN')}` : `${currency} ${n.toLocaleString()}`)
439	    : '—');
440	  const savePct = product.originalPrice && product.price && product.originalPrice > product.price
441	    ? Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100)
442	    : 0;
443	
444	  const inWishlist = !!(rawProduct && isInWishlist(rawProduct.id));
445	  const wishlistBusy = !!(rawProduct && wishPending.has(rawProduct.id));
446	
447	  return (
448	    <div className={styles.pdp}>
449	      <div className={styles.pdpBg} aria-hidden="true">
450	        <DynamicSvgEffect className={`${styles.bgArt} ${styles.bgPeacock}`} effect="lightsweep" sweepAngle={135} inkColor="#B22222">
451	          <img className={styles.bgImg} src="/theme_images/peacock-art-white.png" alt="" />
452	        </DynamicSvgEffect>
453	        <DynamicSvgEffect className={`${styles.bgArt} ${styles.bgMandala}`} effect="lightsweep" sweepAngle={120} inkColor="#B22222">
454	          <img className={styles.bgImg} src="/theme_images/templefront-white.png" alt="" />
455	        </DynamicSvgEffect>
456	        <DynamicSvgEffect className={`${styles.bgArt} ${styles.bgElephant}`} effect="lightsweep" sweepAngle={150} inkColor="#B22222">
457	          <img className={styles.bgImg} src="/theme_images/elephant-art-white.png" alt="" />
458	        </DynamicSvgEffect>
459	        <DynamicSvgEffect className={`${styles.bgArt} ${styles.bgSvgBand}`} effect="lightsweep" sweepAngle={120} inkColor="#B22222">
460	          <img className={styles.bgImg} src="/theme_images/Godess-lakshmi white.png" alt="" />
461	        </DynamicSvgEffect>
462	      </div>
463	
464	      <nav className={styles.crumbs} aria-label="Breadcrumb">
465	        <a href="/">Home</a>
466	        <span className={styles.sep}>/</span>
467	        <a href="/products">Products</a>
468	        <span className={styles.sep}>/</span>
469	        <span className={styles.here}>{product.title}</span>
470	      </nav>
471	
472	      <ErrorBoundary>
473	        <div className={styles.productGrid}>
474	          <div className={styles.leftCol}>
475	            <Gallery
476	              images={images}
477	              activeIdx={activeIdx}
478	              setActiveIdx={setActiveIdx}
479	              onOpenLightbox={(i) => setLightbox({ open: true, idx: i })}
480	              productTitle={product.title}
481	            />
482	            <MaterialStory />
483	          </div>
484	
485	          <div className={styles.info}>
486	            <div className={styles.eyebrow}>
487	              <span className={styles.eyebrowGlyph} /> Hand-Carved · Tadipatri Atelier
488	            </div>
489	            <h1 className={styles.productTitle}>{product.title}</h1>
490	            {product.subtitle && <p className={styles.subtitle}>{product.subtitle}</p>}
491	
492	            <div className={styles.ornamentDivider}>
493	              <span className={styles.dividerLine} />
494	              <span className={styles.dividerGlyph}>✦</span>
495	              <span className={styles.dividerLine} />
496	            </div>
497	
498	            <div className={styles.priceRow}>
499	              <span className={styles.price}>{fmt(product.price)}</span>
500	              {product.originalPrice && product.originalPrice > (product.price || 0) && (
501	                <>
502	                  <span className={styles.strike}>{fmt(product.originalPrice)}</span>
503	                  <span className={styles.savePill}>Save {savePct}%</span>
504	                </>
505	              )}
506	            </div>
507	
508	            <div className={styles.detailsBox}>
509	              {product.material && (
510	                <div className={styles.detailsRow}>
511	                  <span className={styles.detailsLabel}>Material</span>
512	                  <span className={styles.detailsValue}>{product.material}</span>
513	                </div>
514	              )}
515	              {product.dimensions && (
516	                <div className={styles.detailsRow}>
517	                  <span className={styles.detailsLabel}>Dimensions</span>
518	                  <span className={styles.detailsValue}>{product.dimensions}</span>
519	                </div>
520	              )}
521	              {product.weight != null && (
522	                <div className={styles.detailsRow}>
523	                  <span className={styles.detailsLabel}>Weight</span>
524	                  <span className={styles.detailsValue}>
525	                    {product.weight} {product.weightUnit || 'g'}
526	                  </span>
527	                </div>
528	              )}
529	              <div className={styles.detailsRow}>
530	                <span className={styles.detailsLabel}>Availability</span>
531	                <span className={`${styles.stock} ${!product.inStock ? styles.stockOut : ''}`}>
532	                  <span className={`${styles.stockDot} ${!product.inStock ? styles.stockDotOut : ''}`} />
533	                  {product.inStock ? 'In Stock' : 'Out of Stock'}
534	                </span>
535	              </div>
536	            </div>
537	
538	            {product.description && <Description text={product.description} />}
539	
540	            <div className={`${styles.buyBox} ${styles.buyBoxSticky}`}>
541	              <div className={styles.qtyRow}>
542	                <span className={styles.qtyLabel}>Quantity</span>
543	                <div className={styles.qty}>
544	                  <button onClick={() => setQty(q => Math.max(1, q - 1))} disabled={qty <= 1} aria-label="Decrease quantity">
545	                    <MinusI />
546	                  </button>
547	                  <span className={styles.qtyValue}>{qty}</span>
548	                  <button onClick={() => setQty(q => Math.min(10, q + 1))} disabled={qty >= 10} aria-label="Increase quantity">
549	                    <PlusI />
550	                  </button>
551	                </div>
552	              </div>
553	              <p className={styles.shipNote}>Free shipping on orders over $50</p>
554	              <div className={styles.actions}>
555	                <button
556	                  className={styles.cta}
557	                  onClick={handleAddToCart}
558	                  disabled={!product.inStock || state.isAddingToCart || cartLoading}
559	                >
560	                  {(state.isAddingToCart || cartLoading) ? (
561	                    <>
562	                      <LoadingSpinner size="small" color="white" />
563	                      <span>Adding…</span>
564	                    </>
565	                  ) : !product.inStock ? (
566	                    <span>Out of Stock</span>
567	                  ) : (
568	                    <>
569	                      <ChiselI />
570	                      <span>Add to Cart</span>
571	                    </>
572	                  )}
573	                </button>
574	                <button
575	                  className={`${styles.wish} ${inWishlist ? styles.wishActive : ''}`}
576	                  aria-label={inWishlist ? 'Remove from wishlist' : 'Add to wishlist'}
577	                  disabled={wishlistBusy}
578	                  onClick={async () => {
579	                    if (!rawProduct) return;
580	                    if (!wishAuth) { window.location.href = '/login'; return; }
581	                    await toggleWishlist(rawProduct.id);
582	                  }}
583	                >
584	                  <HeartI filled={inWishlist} />
585	                </button>
586	              </div>
587	              {state.addToCartSuccess && (
588	                <div className={`${styles.feedback} ${styles.feedbackSuccess}`}>Added to cart</div>
589	              )}
590	              {state.addToCartError && (
591	                <div className={`${styles.feedback} ${styles.feedbackError}`}>{state.addToCartError}</div>
592	              )}
593	            </div>
594	          </div>
595	        </div>
596	
597	        <CraftStrip />
598	
599	        <div className={styles.reviewsWrap}>
600	          {/* Demoing the empty state by passing an explicit []. Drop the
601	              prop (or pass real reviews) to switch to the populated view. */}
602	          <Reviews reviews={[]} />
603	        </div>
604	
605	        <div className={styles.similarWrap}>
606	          <SimilarProductsSection current={product} />
607	        </div>
608	      </ErrorBoundary>
609	
610	      <Lightbox
611	        open={lightbox.open}
612	        idx={lightbox.idx}
613	        images={images}
614	        onClose={() => setLightbox(s => ({ ...s, open: false }))}
615	        onPrev={() => setLightbox(s => ({ ...s, idx: (s.idx - 1 + images.length) % images.length }))}
616	        onNext={() => setLightbox(s => ({ ...s, idx: (s.idx + 1) % images.length }))}
617	      />
