/* ============================================================
   Product Details Page (NEW design) — Shila Murti
   Ported from shila-murti-design-system/project/pdp.css
   Scoped via CSS Modules. The global Header from layout.tsx
   stays in place; this module styles only the page body.
   ============================================================ */

/* PAGE WRAPPER
   Full viewport width — the bg-art layer (.pdpBg) inherits this so the
   line arts can sit naturally at the screen edges instead of being clipped
   at a 1320px content cap. Inner content blocks (.crumbs, .productGrid,
   .craftStrip, .similarWrap) are individually max-width'd to keep reading
   widths comfortable. */
.pdp {
  width: 100%;
  margin: 0;
  padding: 6rem clamp(1rem, 4vw, 4rem) 4rem;
  position: relative;
  font-family: var(--font-inter), system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  color: #1c1917;
  --shila-ink: #1c1917;
  --shila-paper: #f4ecd8;
  --shila-paper-2: #ebe3cf;
  --shila-paper-3: #d9cfb4;
  --shila-red-deep: #7a1414;
  --shila-gray-2: #444444;
  --shila-gray-3: #6b6b6b;
  --shila-gray-4: #9a9a9a;
  --shila-gray-5: #cfcfcf;
  --font-display: var(--font-cinzel), "Times New Roman", serif;
  --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-soft: cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

/* Soft warm vignette + shader-wash mood — merged into a single fixed
   layer (was two ::before/::after). Same five gradients, same look,
   one full-viewport compositor surface instead of two. */
.pdp::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: -2;
  pointer-events: none;
  background:
    radial-gradient(1100px 700px at 75% 10%, rgba(178, 34, 34, 0.05), transparent 65%),
    radial-gradient(900px 700px at 8% 60%, rgba(40, 40, 60, 0.05), transparent 70%),
    radial-gradient(1100px 800px at 88% 12%, rgba(244, 236, 216, 0.55), transparent 62%),
    radial-gradient(900px 700px at 4% 38%, rgba(244, 236, 216, 0.32), transparent 60%),
    radial-gradient(1000px 700px at 50% 105%, rgba(244, 236, 216, 0.28), transparent 65%),
    #ffffff;
}

/* Background art layer (scrolls with page) */
.pdpBg {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  overflow: hidden;
  /* Single radial-gradient mask feathers all four edges in one pass.
     The previous double-linear + mask-composite: intersect forced an
     extra compositor flatten on every scroll frame across the wrapper
     holding all 4 multiply-blended bg arts. Same edge-fade visual,
     one composite pass instead of two. */
  mask-image: radial-gradient(ellipse 96% 98% at 50% 50%, black 78%, transparent 100%);
  -webkit-mask-image: radial-gradient(ellipse 96% 98% at 50% 50%, black 78%, transparent 100%);
}
.pdp > :not(.pdpBg):not(.ornamentCorner) {
  position: relative;
  z-index: 1;
}
.pdpBg .bgArt {
  position: absolute;
  user-select: none;
  pointer-events: none;
  display: block;
}
.pdpBg .bgImg {
  width: 100%;
  display: block;
  pointer-events: none;
  user-select: none;
  filter: grayscale(100%) contrast(1.05) brightness(0.65);
  /* Soft elliptical vignette so the natural edges of each PNG/SVG fade
     into the page instead of clipping abruptly. Applies to both the base
     img and the cloned filter img inside the sweep layer. */
  mask-image: radial-gradient(ellipse 92% 92% at 50% 50%, black 45%, transparent 100%);
  -webkit-mask-image: radial-gradient(ellipse 92% 92% at 50% 50%, black 45%, transparent 100%);
}
.pdpBg .bgPeacock {
  top: 120px;
  right: -2vw;
  width: min(38vw, 720px);
  opacity: 0.9;
  mix-blend-mode: multiply;
}
.pdpBg .bgMandala {
  top: 1200px;
  left: -2vw;
  right: auto;
  width: min(28vw, 540px);
  opacity: 0.9;
  mix-blend-mode: multiply;
}
.pdpBg .bgElephant {
  top: 1850px;
  right: -2vw;
  width: min(38vw, 720px);
  opacity: 0.9;
  mix-blend-mode: multiply;
}
.pdpBg .bgSvgBand {
  top: 2400px;
  left: -10vw;
  right: auto;
  width: min(38vw, 720px);
  opacity: 0.9;
  mix-blend-mode: multiply;
}

/* Inner content blocks — kept at a comfortable reading width and centered
   within the full-width .pdp. The bg-art layer underneath spans the full
   viewport so arts can hug the screen edges. */
.crumbs,
.productGrid,
.craftStrip,
.reviewsWrap,
.similarWrap {
  max-width: 1320px;
  margin-left: auto;

