1	import React, { useState, useRef, useId, useCallback, useEffect } from 'react';
2	import { useMotionValue, useSpring, useMotionValueEvent } from 'framer-motion';
3	import styles from './DynamicSvgEffect.module.css';
4	import { registerWindowSweep } from './windowSweepRegistry';
5	
6	interface DynamicSvgEffectProps {
7	  /** A single React element, expected to be an SVG. */
8	  children: React.ReactElement;
9	  /** The size of the spotlight mask in pixels. Default is 400. */
10	  spotlightSize?: number;
11	  /** The color of the specular light highlight. Default is '#FFFFFF'. */
12	  lightColor?: string;
13	  /** The brightness of the specular highlight (0 to 1). Default is 0.75. */
14	  specularConstant?: number;
15	  /** The "tightness" or "shininess" of the highlight. Higher values create a smaller, sharper glint. Default is 25. */
16	  specularExponent?: number;
17	  /** Custom className for the container */
18	  className?: string;
19	  /** Custom styles for the container */
20	  containerStyle?: React.CSSProperties;
21	  /** Enable viewport culling for performance. Default is true. */
22	  enableViewportCulling?: boolean;
23	  /** Margin around viewport for intersection observer. Default is '100px'. */
24	  viewportMargin?: string;
25	  /**
26	   * Visual effect preset.
27	   * - 'specular' (default): cursor-driven white specular highlight.
