file.content:
.container {
  position: relative;
  display: inline-block;
  transform: translateZ(0); /* Force hardware acceleration */
  will-change: opacity; /* Hint to browser about opacity changes */
  contain: layout style paint; /* CSS containment for better performance */
  backface-visibility: hidden; /* Prevent flickering */
  perspective: 1000px; /* Create stacking context */
}

.baseLayer {
  transition: opacity 200ms ease-out;
  transform: translateZ(0); /* Force hardware acceleration */
}

.effectLayer {
  position: absolute;
  inset: 0;
  transition: opacity 200ms ease-out;
  transform: translateZ(0); /* Force hardware acceleration */
  will-change: opacity; /* Hint to browser about opacity changes */
}

.ambientLayer {
  opacity: 0.2;
  transform: translateZ(0); /* Force hardware acceleration */
}

.spotlightLayer {
  position: absolute;
  inset: 0;
  transform: translateZ(0); /* Force hardware acceleration */
  will-change: mask-image, -webkit-mask-image; /* Hint to browser about mask changes */
}

/* lightsweep — scroll-driven mask-position. JS sets --sweep-pos on the
   wrapper from the element's scroll progress (rAF-throttled). The band
   peak stays on the art at all times (range clamped to keep gradient
   50% within the visible window). */
.sweepLayer {
  mask-position: var(--sweep-pos, 50%) var(--sweep-pos, 50%);
  -webkit-mask-position: var(--sweep-pos, 50%) var(--sweep-pos, 50%);
  will-change: mask-position, -webkit-mask-position;
}

.filterDefinition {
  position: absolute;
  width: 0;
  height: 0;
  pointer-events: none;
}

