  //   y travels top → bottom (with a small off-frame overshoot at each end
  //   so the art is fully dim at p=0 and p=1 — gives the "light arrives,
  //   light leaves" cinematic moment).
  //   x stays anchored near one side and bows inward at midpoint via a
  //   half-sine (peak at p=0.5). Direction of bow flips with rimSide so
  //   the curve always arcs toward the element's interior.
  const anchorX = rimSide === 'right' ? 82 : 18;
  const sign = rimSide === 'right' ? -1 : 1;
  const bow = bowAmplitude * Math.sin(Math.PI * p);
  const x = anchorX + sign * bow;
  const y = -bowOvershoot + (100 + 2 * bowOvershoot) * p;
  el.style.setProperty('--spot-x', `${x}%`);
  el.style.setProperty('--spot-y', `${y}%`);
